        // still fold because fcmp(X,0) == fcmp(-X,0) for these predicates.
        switch (I.getPredicate()) {
        case FCmpInst::FCMP_OEQ:
        case FCmpInst::FCMP_UEQ:
        case FCmpInst::FCMP_ONE:
        case FCmpInst::FCMP_UNE:
        case FCmpInst::FCMP_ORD:
        case FCmpInst::FCMP_UNO:
          break;
        default:
          return nullptr;
        }
      }
    }
    // Check for arms: X, (fneg X)
    else if (match(FalseVal, m_FNeg(m_Value(X))) &&
             match(TrueVal, m_Specific(X))) {
      // Check if this is the fabs pattern: cond is (fcmp oge/ogt/uge/ugt X, 0)
      bool IsFabs = match(Cond, m_FCmp(P, m_Specific(X), m_AnyZeroFP())) &&
                    (P == FCmpInst::FCMP_OGE || P == FCmpInst::FCMP_OGT ||
                     P == FCmpInst::FCMP_UGE || P == FCmpInst::FCMP_UGT);
      if (!IsFabs) {
        // Not the fabs pattern. For equality/ord/uno outer predicates, we can
        // still fold because fcmp(X,0) == fcmp(-X,0) for these predicates.
        switch (I.getPredicate()) {
        case FCmpInst::FCMP_OEQ:
        case FCmpInst::FCMP_UEQ:
        case FCmpInst::FCMP_ONE:
        case FCmpInst::FCMP_UNE:
        case FCmpInst::FCMP_ORD:
        case FCmpInst::FCMP_UNO:
          break;
        default:
          return nullptr;
        }
      }
    } else {
      return nullptr;
    }
  }
